  //          if (page < 1 || page > 1000) return res.status(400).json({ error: 'Invalid page' });
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});

// --- 404 Handler ---
